/**
 * Claude Hooks Compile Target
 *
 * Reads hook sources from `.minsky/hooks/*.ts` (excluding `*.test.ts`) and
 * emits `.claude/hooks/<name>.ts` with:
 *   - `#!/usr/bin/env bun` shebang on line 1 (stripped from source if already
 *     present, then re-added fresh so compiled outputs are always consistent)
 *   - `// Generated by minsky compile. Do not edit directly.` banner on line 2
 *     (recognised by `.claude/hooks/check-generated-file-edit.ts` via the
 *     `// Generated by` pattern in `GENERATION_BANNER_PATTERNS`)
 *   - `// Source: .minsky/hooks/<name>.ts` provenance comment on line 3
 *   - The source content verbatim below
 *   - File permissions set to `0o755` (executable) via `fs.chmod`
 *
 * Part of the ADR-016 unified compile pipeline (mt#2280). Closes the asymmetry
 * where hooks were the only Claude Code authoring surface without a
 * Minsky-native source at `.minsky/`.
 *
 * @see mt#2304 — implementation task
 * @see mt#2280 / ADR-016 — compile pipeline convergence (parent)
 * @see .claude/hooks/check-generated-file-edit.ts — banner recognition
 */

import { join, basename } from "path";
import realFs from "fs/promises";
import type {
  MinskyCompileTarget,
  MinskyCompileResult,
  MinskyTargetOptions,
  MinskyCompileFsDeps,
} from "../types";

// ---------------------------------------------------------------------------
// Constants (exported so tests can reference without duplicating strings)
// ---------------------------------------------------------------------------

export const HOOK_SHEBANG = "#!/usr/bin/env bun";
export const HOOK_COMPILE_BANNER = "// Generated by minsky compile. Do not edit directly.";
export const HOOK_FILE_MODE = 0o755;

/**
 * Source directory where hooks are authored.
 * Pattern: `.minsky/hooks/<name>.ts`
 */
function hookSourceDir(workspacePath: string): string {
  return join(workspacePath, ".minsky", "hooks");
}

/**
 * Root output directory for compiled hooks.
 * Output: .claude/hooks/<name>.ts
 */
function hookOutputDir(workspacePath: string): string {
  return join(workspacePath, ".claude", "hooks");
}

/** Absolute path to the compiled output for a given hook filename. */
function hookOutputPath(workspacePath: string, hookFileName: string): string {
  return join(hookOutputDir(workspacePath), hookFileName);
}

// ---------------------------------------------------------------------------
// Content builder
// ---------------------------------------------------------------------------

/**
 * Build the compiled content for a hook source file.
 *
 * The banner header is always:
 *   #!/usr/bin/env bun
 *   // Generated by minsky compile. Do not edit directly.
 *   // Source: .minsky/hooks/<name>.ts
 *
 * If the source already has a `#!/usr/bin/env bun` shebang on line 1,
 * it is stripped before building (we always add it fresh so the output
 * is deterministic regardless of whether the source has one).
 */
export function buildHookContent(sourceContent: string, hookFileName: string): string {
  // Strip leading shebang if present so we always start from clean content
  const strippedContent = sourceContent.startsWith(`${HOOK_SHEBANG}\n`)
    ? sourceContent.slice(`${HOOK_SHEBANG}\n`.length)
    : sourceContent;

  const provenance = `// Source: .minsky/hooks/${hookFileName}`;

  return `${HOOK_SHEBANG}\n${HOOK_COMPILE_BANNER}\n${provenance}\n\n${strippedContent}`;
}

// ---------------------------------------------------------------------------
// Source discovery
// ---------------------------------------------------------------------------

/**
 * List `*.ts` source filenames under `.minsky/hooks/` (excluding `*.test.ts`).
 * Returns only the bare filename (e.g. `substrate-bypass-detector.ts`).
 */
async function discoverHookSourceFiles(
  workspacePath: string,
  fs: MinskyCompileFsDeps
): Promise<string[]> {
  const sourceDir = hookSourceDir(workspacePath);
  let entries: string[];
  try {
    entries = await fs.readdir(sourceDir);
  } catch {
    return [];
  }

  return entries.filter(
    (name) =>
      name.endsWith(".ts") &&
      !name.endsWith(".test.ts") &&
      // Skip non-TS files (e.g. .md reference docs, SPEC.md)
      !name.endsWith(".md")
  );
}

// ---------------------------------------------------------------------------
// Target factory
// ---------------------------------------------------------------------------

/** Build the claude-hooks target. Factory pattern for test injection. */
function makeClaudeHooksTarget(): MinskyCompileTarget {
  return {
    id: "claude-hooks",
    displayName: "Claude Hooks",
    // .claude/hooks/ is exclusively owned by this compile target once the
    // migration is complete — no hand-authored files remain there.
    // Setting sharedOutputDirectory: false enables orphan detection in
    // --check mode so stale outputs are caught.
    sharedOutputDirectory: false,

    defaultOutputPath(workspacePath: string): string {
      return hookOutputDir(workspacePath);
    },

    async listOutputFiles(
      _options: MinskyTargetOptions,
      workspacePath: string,
      fsDeps?: MinskyCompileFsDeps
    ): Promise<string[]> {
      const fs = fsDeps ?? (realFs as MinskyCompileFsDeps);
      const fileNames = await discoverHookSourceFiles(workspacePath, fs);
      return fileNames.map((name) => hookOutputPath(workspacePath, name));
    },

    async compile(
      options: MinskyTargetOptions,
      workspacePath: string,
      fsDeps?: MinskyCompileFsDeps
    ): Promise<MinskyCompileResult> {
      const fs = fsDeps ?? (realFs as MinskyCompileFsDeps);
      const fileNames = await discoverHookSourceFiles(workspacePath, fs);

      const filesWritten: string[] = [];
      const definitionsIncluded: string[] = [];
      const definitionsSkipped: string[] = [];
      const contentsByPath = new Map<string, string>();
      const dryRunParts: string[] = [];

      for (const fileName of fileNames) {
        const sourcePath = join(hookSourceDir(workspacePath), fileName);

        let sourceContent: string;
        try {
          sourceContent = await fs.readFile(sourcePath, "utf-8");
        } catch (error) {
          const reason = error instanceof Error ? error.message : String(error);
          // Do not swallow silently — surface the error so operators know the
          // source was skipped. Mirrors the claude-skills pattern (mt#2182).
          definitionsSkipped.push(fileName);
          // Log to stderr only; we don't have access to the logger here to
          // avoid a circular dependency — callers can enable debug logging.
          process.stderr.write(
            `[compile:claude-hooks] skipping "${fileName}": failed to read ${sourcePath}: ${reason}\n`
          );
          continue;
        }

        const outputPath = hookOutputPath(workspacePath, fileName);
        const content = buildHookContent(sourceContent, basename(sourcePath));

        if (options.dryRun) {
          contentsByPath.set(outputPath, content);
          dryRunParts.push(`// ${outputPath}\n${content}`);
        } else {
          await fs.mkdir(hookOutputDir(workspacePath), { recursive: true });
          await fs.writeFile(outputPath, content, "utf-8");
          // Make the compiled hook executable (0o755) so Claude Code and
          // bun can run it directly. The Write tool sets 0o644 by default;
          // without chmod the hook silently fails to execute.
          await fs.chmod(outputPath, HOOK_FILE_MODE);
        }

        filesWritten.push(outputPath);
        definitionsIncluded.push(fileName);
      }

      return {
        target: "claude-hooks",
        filesWritten,
        definitionsIncluded,
        definitionsSkipped,
        content: options.dryRun ? dryRunParts.join("\n\n") : undefined,
        contentsByPath: options.dryRun ? contentsByPath : undefined,
      };
    },
  };
}

export const claudeHooksTarget = makeClaudeHooksTarget();

/** Export factory for test injection */
export { makeClaudeHooksTarget };
